// Marca processando e publica imediatamente via Zernio
const {
  id, tipo_post, legenda, hashtags, imagem_url, video_url,
  SUPABASE_URL, SUPABASE_KEY, ZERNIO_API_KEY, ZERNIO_ACCOUNT_ID
} = $input.item.json;

// Marca processando
await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/posts_instagram?id=eq.${id}`,
  headers: {
    apikey: SUPABASE_KEY,
    Authorization: `Bearer ${SUPABASE_KEY}`,
    'Content-Type': 'application/json',
    Prefer: 'return=minimal'
  },
  body: { status: 'processando' },
  json: true
});

const caption = [legenda, hashtags].filter(Boolean).join('\n\n');

let body;

if (tipo_post === 'carrossel') {
  const midias = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/post_midias?post_id=eq.${id}&order=ordem.asc`,
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` },
    json: true
  });
  if (!midias || midias.length < 2) throw new Error(`Carrossel precisa de pelo menos 2 imagens. Encontrado: ${midias?.length ?? 0}`);
  body = {
    platforms: [{ platform: 'instagram', accountId: ZERNIO_ACCOUNT_ID }],
    content: caption,
    mediaItems: midias.map(m => ({ type: m.tipo || 'image', url: m.imagem_url })),
    publishNow: true
  };
} else {
  const mediaItems = [];
  if (tipo_post === 'reel' && video_url) {
    mediaItems.push({ type: 'video', url: video_url });
  } else if (imagem_url) {
    mediaItems.push({ type: 'image', url: imagem_url });
  }
  body = {
    platforms: [{ platform: 'instagram', accountId: ZERNIO_ACCOUNT_ID }],
    content: caption,
    publishNow: true,
    ...(tipo_post === 'story' ? { postType: 'story' } : {}),
    ...(tipo_post === 'reel' ? { postType: 'reel' } : {}),
    ...(mediaItems.length > 0 ? { mediaItems } : {})
  };
}

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://zernio.com/api/v1/posts',
  headers: { 'Authorization': `Bearer ${ZERNIO_API_KEY}`, 'Content-Type': 'application/json' },
  body,
  json: true
});

if (res.error) throw new Error(`Zernio erro: ${JSON.stringify(res)}`);

// Marca publicado
await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/posts_instagram?id=eq.${id}`,
  headers: {
    apikey: SUPABASE_KEY,
    Authorization: `Bearer ${SUPABASE_KEY}`,
    'Content-Type': 'application/json',
    Prefer: 'return=minimal'
  },
  body: {
    status: 'publicado',
    instagram_media_id: res.id || res.postId || '',
    publicado_em: new Date().toISOString(),
    erro_msg: null
  },
  json: true
});

return [{ json: { success: true, post_id: id, media_id: res.id || res.postId } }];

