const execData = $input.item.json;

const postId = Object.values(execData?.data?.resultData?.runData || {})
  .flat()
  .map(r => r?.data?.main?.[0]?.[0]?.json?.id)
  .find(Boolean) ?? null;

const erroMsg = execData?.data?.resultData?.error?.message
  || execData?.message
  || 'Erro desconhecido no workflow';

if (!postId) {
  return [{ json: { aviso: 'Post ID não identificado', erro: erroMsg } }];
}

const postRes = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/posts_instagram?id=eq.${postId}&select=tentativas,max_tentativas`,
  headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` },
  json: true
});

const post = postRes?.[0];
const tentativas = (post?.tentativas || 0) + 1;
const max = post?.max_tentativas || 3;
const novoStatus = tentativas >= max ? 'erro' : 'agendado';

await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/posts_instagram?id=eq.${postId}`,
  headers: {
    apikey: SUPABASE_KEY,
    Authorization: `Bearer ${SUPABASE_KEY}`,
    'Content-Type': 'application/json',
    Prefer: 'return=minimal'
  },
  body: { status: novoStatus, tentativas, erro_msg: erroMsg },
  json: true
});

return [{ json: { post_id: postId, status: novoStatus, tentativas, erro: erroMsg } }];
